async function run(params, api) {
  var method = params.method || 'GET';
  api.log(method + ' ' + params.url);
  var raw;
  if (method === 'POST') {
    var body = params.body ? JSON.stringify(params.body) : '';
    var headers = params.headers || {};
    headers['Content-Type'] = headers['Content-Type'] || 'application/json';
    raw = await api.httpPost(params.url, body, headers);
  } else {
    raw = await api.httpGet(params.url);
  }
  try {
    var parsed = JSON.parse(raw);
    return JSON.stringify(parsed, null, 2);
  } catch (e) {
    if (raw.length > 10000) raw = raw.slice(0, 10000) + '\n... [truncated]';
    return raw;
  }
}
